    // such that their XOR sum is j.
    // However, since we are minimizing removals, it's easier to track the minimum *removals*.
    // dp[i][j] = minimum removals from nums[0...i-1] to achieve XOR sum j.
    // Since N is small (<= 40), 2^10000 is too large for DP state on XOR sum.
    // Let's re-examine the constraints and problem type.

    // N <= 40 suggests an exponential solution like meet-in-the-middle (2^20 * 2^20) or DP with smaller states.
    // Max XOR sum is bounded by 2^14 (since max nums[i] <= 10^4 < 2^14). Let M = 2^14.
    // DP state: dp[i][j] = boolean indicating if XOR sum j is achievable using a subset of nums[0...i-1].
    // If we use DP, we can track the minimum removals to achieve j.

    // Max possible XOR sum is less than 2^14 = 16384. Let MAX_XOR = 2^14.
    const MAX_XOR = 16384;

    // dp[j] stores the minimum number of elements *kept* to achieve XOR sum j using elements processed so far.
    // Initialize with a value larger than N (N+1).
    const INF = n + 1;
    let dp: number[] = new Array(MAX_XOR).fill(INF);

    // Base case: XOR sum 0 is achievable with 0 elements kept (0 removals from empty set).
    dp[0] = 0;

