                // We kept one more element, so the count increases by 1.
                const new_kept_count = dp[j] + 1;

                // Update next_dp[new_xor] if this path yields fewer kept elements.
                // Since we are minimizing removals, minimizing kept elements is NOT the goal.
                // We want to minimize removals = N - kept_count. This means maximizing kept_count.

                // Let's redefine DP:
                // dp[j] = Maximum number of elements kept from processed prefix to achieve XOR sum j.

                // --- RESTARTING DP DEFINITION ---
                // dp[j] = Maximum size of a subset of processed elements whose XOR sum is j.
            }
        }
    }

    // --- Corrected DP approach ---
    // dp[j]: Maximum size of a subset of elements processed so far whose XOR sum is j.

    const MAX_XOR_VAL = 1 << 14; // 16384
    const INF_KEPT = -1; // Impossible to achieve
    let max_kept_count: number[] = new Array(MAX_XOR_VAL).fill(INF_KEPT);

    // Base case: XOR sum 0 is achievable with 0 elements.
    max_kept_count[0] = 0;

    for (const num of nums) {
