                const new_xor = j ^ num;
                const new_kept_count = max_kept_count[j] + 1;

                // Update the maximum kept count for new_xor
                next_max_kept_count[new_xor] = Math.max(
                    next_max_kept_count[new_xor],
                    new_kept_count
